+    let value = golden[section][field]
+        .as_u64()
+        .unwrap_or_else(|| panic!("golden {section}.{field} should be u64"));
+    u8::try_from(value)
+        .unwrap_or_else(|_| panic!("golden {section}.{field}={value} does not fit in u8"))
